import { AlertModel } from "./alertModel";

/**
 * 有 confirm button 的訊息窗。
 */
export class ConfirmAlert extends AlertModel {
  /**
   * 顯示成功訊息。
   * @param {string} [msg = ""] 成功訊息，應簡短扼要。
   */
  static alertSuccess(msg = "") {
    this.mixTitle(this.successModel, msg).fire();
  }

  /**
   * 顯示警告訊息。
   * @param {string} [msg = ""] 警告訊息，應簡短扼要。
   */
  static alertWarning(msg = "") {
    this.mixTitle(this.warningModel, msg).fire();
  }

  /**
   * 顯示警告訊息，會列出標題及說明。
   * @param {string} [msg = ""] 警告訊息，應簡短扼要。
   * @param {string} [detail = ""] 說明。
   */
  static alertWarningDetail(msg = "", detail = "") {
    this.mixTitleDesc(this.warningModel, msg, detail).fire();
  }

  /**
   * 顯示錯誤訊息，具有強制注意的效果。
   * @param {string} [msg = ""] 錯誤訊息，應簡短扼要。
   */
  static alertError(msg = "") {
    this.mixTitleDesc(this.errorModel, msg).fire();
  }

  /**
   * 顯示錯誤訊息，會列出標題及說明，並具有強制注意的效果。
   * @param {string} [title = ""] 標題，應簡短扼要。
   * @param {string} [detail = ""] 說明。
   */
  static alertErrorDetail(title = "", detail = "") {
    this.mixTitleDesc(this.errorModel, title, detail).fire();
  }
}
